```csharp
using System.Net.WebSockets;
using System.Text.Json;
using Microsoft.Extensions.Options;

namespace Meridian.Infrastructure.Alpaca;

public class AlpacaStreamClient : IMarketDataClient
{
    private ClientWebSocket? _ws;
    private readonly IOptions<AlpacaSettings> _settings;
    private readonly ILogger<AlpacaStreamClient> _logger;
    private bool _isConnected;

    public AlpacaStreamClient(IOptions<AlpacaSettings> settings, ILogger<AlpacaStreamClient> logger)
    {
        _settings = settings;
        _logger = logger;
    }

    public async Task ConnectAsync(CancellationToken ct = default)
    {
        _ws = new ClientWebSocket();
        await _ws.ConnectAsync(new Uri(_settings.Value.WebSocketUrl), ct);
        _isConnected = true;
        _logger.LogInformation($"Connected to Alpaca at {_settings.Value.WebSocketUrl}");
    }

    public async Task SubscribeAsync(IEnumerable<string> symbols, CancellationToken ct = default)
    {
        var msg = JsonSerializer.Serialize(new { action = "subscribe", trades = symbols });
        var bytes = System.Text.Encoding.UTF8.GetBytes(msg);
        await _ws!.SendAsync(bytes, WebSocketMessageType.Text, true, ct);
    }

    public async IAsyncEnumerable<MarketEvent> StreamEventsAsync(
        [System.Runtime.CompilerServices.EnumeratorCancellation] CancellationToken ct = default)
    {
        var buffer = new byte[4096];
        while (_ws!.State == WebSocketState.Open)
        {
            var result = await _ws.ReceiveAsync(buffer, CancellationToken.None);
            if (result.MessageType == WebSocketMessageType.Close)
                break;

            var json = System.Text.Encoding.UTF8.GetString(buffer, 0, result.Count);
            var evt = JsonSerializer.Deserialize<MarketEvent>(json);
            if (evt != null)
                yield return evt;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_ws != null)
        {
            await _ws.CloseAsync(WebSocketCloseStatus.NormalClosure, "Shutting down", CancellationToken.None);
            _ws.Dispose();
        }
    }
}
