using System.Text.Json;
using Microsoft.Extensions.Logging;
using Meridian.Contracts.Domain.Events;

namespace Meridian.Storage.Sinks;

public class JsonlStorageSink : IStorageSink
{
    private readonly string _rootPath;
    private readonly ILogger<JsonlStorageSink> _logger;

    public JsonlStorageSink(string rootPath, ILogger<JsonlStorageSink> logger)
    {
        _rootPath = rootPath;
        _logger = logger;
    }

    public async ValueTask WriteAsync(MarketEvent evt, CancellationToken ct = default)
    {
        var date = evt.Timestamp.Date.ToString("yyyy-MM-dd");
        var path = Path.Combine(_rootPath, evt.Symbol, date + ".jsonl");
        Directory.CreateDirectory(Path.GetDirectoryName(path)!);

        var json = JsonSerializer.Serialize(evt) + "\n";
        await File.AppendAllTextAsync(path, json, ct);
        _logger.LogDebug($"Wrote event for {evt.Symbol} to {path}");
    }

    public Task FlushAsync(CancellationToken ct = default)
    {
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _logger.LogInformation("JsonlStorageSink disposed");
    }
}
