module Meridian.FSharp.Validation.QuoteValidator

open Meridian.FSharp.Domain

type ValidationResult =
    | Valid of Quote
    | InvalidSpread of spread: decimal * maxAllowed: decimal
    | StaleQuote of ageMs: int64
    | MissingData of field: string

let validateQuote (maxSpreadBps: decimal) (staleThresholdMs: int64) (quote: Quote) : ValidationResult =
    let spread = quote.Ask - quote.Bid
    let spreadBps = if quote.Mid > 0M then (spread / quote.Mid) * 10000M else 0M
    let ageMs = (System.DateTimeOffset.UtcNow - quote.Timestamp).TotalMilliseconds |> int64

    if spreadBps > maxSpreadBps then
        InvalidSpread(spreadBps, maxSpreadBps)
    elif ageMs > staleThresholdMs then
        StaleQuote(ageMs)
    elif quote.Bid <= 0M || quote.Ask <= 0M then
        MissingData("bid/ask")
    else
        Valid(quote)
