using Meridian.FSharp.Validation;
using Meridian.Contracts;

namespace Meridian.Ui.Services;

public class QuoteValidationService
{
    private const decimal MaxSpreadBps = 50m;
    private const long StaleThresholdMs = 5000;

    public bool IsValid(Quote quote)
    {
        var result = QuoteValidator.validateQuote(MaxSpreadBps, StaleThresholdMs, quote);

        if (result.IsValid)
            return true;

        if (result.IsInvalidSpread)
        {
            Console.WriteLine($"Spread too wide: {result.Item1}");
            return false;
        }

        if (result.IsStaleQuote)
        {
            Console.WriteLine($"Quote is stale: {result.Item1}ms old");
            return false;
        }

        return false;
    }
}
