namespace Meridian.Infrastructure.Adapters.Tiingo;

public class TiingoHistoricalProvider : IHistoricalDataProvider
{
    private readonly HttpClient _http;
    private readonly IOptions<TiingoSettings> _settings;

    public string Name => "tiingo";
    public string DisplayName => "Tiingo";
    public string Description => "Daily OHLCV bars from Tiingo";
    public int Priority => 3;

    public HistoricalDataCapabilities Capabilities => new()
    {
        SupportsDailyBars = true,
        SupportsIntradayBars = false,
        SupportsTickData = false
    };

    public TiingoHistoricalProvider(IOptions<TiingoSettings> settings)
    {
        _settings = settings;
        _http = new HttpClient();
        _http.DefaultRequestHeaders.Add("Authorization", $"Token {_settings.Value.ApiToken}");
    }

    public async Task<IReadOnlyList<HistoricalBar>> GetDailyBarsAsync(
        string symbol, DateOnly? from, DateOnly? to)
    {
        var url = $"https://api.tiingo.com/tiingo/daily/{symbol}/prices" +
                  $"?startDate={from}&endDate={to}&token={_settings.Value.ApiToken}";

        var response = await _http.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        var bars = JsonSerializer.Deserialize<List<TiingoPriceResponse>>(json);

        return bars?.Select(b => new HistoricalBar
        {
            Symbol = symbol,
            Date = DateOnly.Parse(b.date),
            Open = b.open,
            High = b.high,
            Low = b.low,
            Close = b.close,
            Volume = b.volume
        }).ToList() ?? new List<HistoricalBar>();
    }
}
